var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"최후의 수단이라 생각한 마지막 카드마저 꺼냈음에도 쓰러지지 않는 금발의 전사.","JPN":"最後の手段であるはずの切り札まで出したのに倒すことができない金髪の戦士。","ENG":"The Blonde Warrior didn't fall even after using what was thought to be a last resort.","TWN":"掏出最後的王牌也打不倒的金髮戰士。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"세상의 정점에 올라 왕좌에 앉는 순간까지 단 한 걸음이었다.","JPN":"世界の頂点に上り詰め王座につく瞬間まであと一歩だった。","ENG":"There was only one step left to reach the pinnacle of the world and claim the throne.","TWN":"距離登上世界之巔的寶座，只剩一步之遙。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"어째서……. 단 한걸음, 고작 단 한걸음만이 남았을 터였다…….","JPN":"どうして……あと一歩、たった一歩足りないだけだった……。","ENG":"But why...? It was in arm's reach, and all it would take was just one more step forward...","TWN":"為什麼……就差一步，就那麼一步……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이건 내가 만들어 놓은 세상이야! 그 누구도 내 법칙에 거스를 순 없었어!","JPN":"これは私が作った世界よ！　誰も私の法則に逆らうことはできなかった！","ENG":"I created this world! No one's been able to defy my laws!","TWN":"這是我所創造的世界！沒有人可以違背我的法則！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 만들어 놓은 세계의 법칙이! 한낱 인간이 바꿀 수 있을 만큼 그렇게 만만해 보여?","JPN":"私が作った世界の法則は！　一介の人間に変えられるほど、そんなに単純なものに見える？","ENG":"Do you think this world's laws that I created are simple enough that a mere human can change them?","TWN":"我所創造的世界法則！難道那麼輕易就能夠被區區的人類改變嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 어떻게…! 너한텐 정말 그게 가능하다는 거야…?!","JPN":"ど、どうして……！　あんたには本当にそれが可能だっていうの……？","ENG":"B-but how...?! How is that even possible...?!","TWN":"怎麼會…！對你來說真的是有可能的嗎…？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"대답해! 너는… 정말 그렇단 말이야?! 애송이, 아니, 나이엘 블루스틸이여!","JPN":"答えて！　あんたは……本当にそうなの！？　小娘、いいえ、ナイエル・ブルースチールよ！","ENG":"Answer me! Can you... really do that?! Kid, no, Naielle Bluesteel!!","TWN":"回答我！你…真的有那麼厲害嗎？！小子，說錯。回答我，奈爾·布魯斯提爾！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어때? 이건 내가 최강의 기사와 펼쳤던 전투를 담은 책이야.\xA0","JPN":"どう？　これは私が戦った最強の騎士との戦闘について記した本よ。","ENG":"What do you think? This is a book that describes my battle against the strongest knight.","TWN":"怎麼樣？這本書裡面寫到的，就是是我跟最強騎士決鬥的故事。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이날 내가 아니었다면, 세계는 진짜 끝장났을지도 모른다고?","JPN":"私が戦ってなかったら、世界は本当に終わっていたかもしれないのよ？","ENG":"If it weren't for me, the world might've really ended.","TWN":"那天要不是有我，說不定就世界末日咧？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"우와……!","JPN":"わあ……！","ENG":"Whoa...!","TWN":"哇喔……！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그럼 언니가 세상에서 제일 강한 거예요?","JPN":"じゃあ、お姉ちゃんは世界一強いの？","ENG":"Then, you're the strongest in the world now?","TWN":"那姊姊不就是世界上最強的人嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼~ 너희들도 나중에 크면 나이엘 선배의 위대함을 잘 기억해 두도록 해.","JPN":"もちろん！　あんたたちも、このナイエル先輩の偉大さをよーく覚えておくことね。","ENG":"Of course! So make sure to never forget the greatness of Naielle Bluesteel when you grow up.","TWN":"那當然～所以你們長大後也不可以忘記奈爾姊姊有多偉大喔。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"훗, 모처럼 연기까지 연습한 보람이 있어. 애들은 참 순진해서 좋다니까.","JPN":"ふっ、演技の練習までしておいた甲斐があった。子どもたちは単純でいいわ。","ENG":"Heh, I guess it was worth practicing my acting. I love how naive kids are.","TWN":"嘿嘿，辛苦練演技總算沒白費，小朋友們還真天真。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"재밌었니? 나이엘 언니가 어제 힘들게 쓰신 거야.","JPN":"面白かった？　ナイエルお姉ちゃんが昨日頑張って書いたお話だよ。","ENG":"Was it fun? Naielle worked hard to write it yesterday.","TWN":"喜歡嗎？這是奈爾姊姊昨天辛苦完成的故事喔。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이건 실화를 기반으로 만든 거라고!","JPN":"こ、これは実話に基づいて書いたんだから！","ENG":"Hey! This is based on a true story!","TWN":"這，這是根據真人真事改編的故事！"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아하하, 그랬었죠. 정말 고생 많으셨어요.","JPN":"あはは、そうでしたね。お疲れさまでした。","ENG":"Ah hah hah, that's right. Great work, Naielle.","TWN":"哈哈哈，是啊。真的辛苦你了。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"언니가 세상에서 제일 강한 카운터래요!","JPN":"お姉ちゃんは世界一強いカウンターだって！","ENG":"She said she's the strongest Counter in the world!","TWN":"姊姊是世界上最強的制裁者！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"전설의 기사랑 싸워서 한방에 이겼대요!","JPN":"伝説の騎士と戦って、一撃で倒したんだよ！","ENG":"She fought against the legendary knight and beat him in one blow!","TWN":"聽說她和傳說中的騎士戰鬥，一招就贏了！"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아하하, 나이엘 학생은 정말 대단하네요.","JPN":"あはは、ナイエルさんは本当にすごいですね。","ENG":"Ah hah hah. You're amazing, Naielle.","TWN":"哈哈哈，奈爾同學真是厲害啊。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"지난겨울 때부터 항상 봉사하러 와 주시고, 정말 든든했답니다.","JPN":"去年の冬から何回もボランティアに来てくださって、心強かったです。","ENG":"You've been coming here to volunteer since last winter, and you've been so helpful.","TWN":"從去年冬天開始你就一直來幫忙，真的很可靠呢。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"혹시…… 오늘이 마지막 날이었죠? 아이들이 많이 슬퍼하겠어요.","JPN":"確か……今日が最後の日ですね。子どもたちが寂しがるでしょう。","ENG":"Today... is your last day, right? The children will be so sad.","TWN":"難道……今天是最後一天嗎？孩子們會很難過的。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어쩔 수 없잖아? 아무리 나라도 평생 봉사만 할 수는 없다고.","JPN":"仕方ないでしょ？　いくら私でも、一生ボランティアはできないもの。","ENG":"It had to end someday. I can't continue volunteering for the rest of my life.","TWN":"沒辦法啊？再怎麼說我也不能一輩子只做志工吧。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};